package typescript

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
	"github.com/Adhamzineldin/Veld/internal/emitter"
)

func init() {
	emitter.RegisterFrontend("typescript", New())
}

// TypeScriptEmitter generates the frontend fetch SDK (generated/client/).
type TypeScriptEmitter struct{}

func (*TypeScriptEmitter) IsFrontend() {}
func New() *TypeScriptEmitter          { return &TypeScriptEmitter{} }

// Summary returns a human-friendly breakdown of generated files.
func (e *TypeScriptEmitter) Summary(modules []string) []emitter.SummaryLine {
	files := []string{"_internal.ts", "api.ts", "types.ts", "errors.ts", "package.json"}
	for _, m := range modules {
		files = append(files, strings.ToLower(m)+"Api.ts")
	}
	return []emitter.SummaryLine{
		{Dir: "client/", Files: strings.Join(files, ", ")},
	}
}

// Emit writes generated/client/ into outDir. Expects types/ and errors/ to
// already exist as siblings (emitted by the backend emitter into the same dir).
func (e *TypeScriptEmitter) Emit(a ast.AST, outDir string, opts emitter.EmitOptions) error {
	if opts.DryRun {
		return nil
	}

	dir := filepath.Join(outDir, "client")
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}

	// 1. _internal.ts — shared error class, BASE URL, HTTP helpers (all exported).
	var internal strings.Builder
	internal.WriteString("// AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	emitErrorClass(&internal)
	emitBaseURL(&internal, opts)
	emitHTTPHelpers(&internal)
	if err := os.WriteFile(filepath.Join(dir, "_internal.ts"), []byte(internal.String()), 0644); err != nil {
		return err
	}

	// 2. Per-module API files: authApi.ts, usersApi.ts, etc.
	for _, mod := range a.Modules {
		if err := emitModuleApi(a, mod, dir); err != nil {
			return fmt.Errorf("module api %s: %w", mod.Name, err)
		}
	}

	// 3. api.ts barrel — re-exports per-module APIs + unified `api` object.
	if err := emitApiBarrel(a, dir); err != nil {
		return fmt.Errorf("api barrel: %w", err)
	}

	// 4. client/types.ts — re-exports all types so frontend can import from @veld/client.
	if err := emitClientTypesBarrel(a, dir); err != nil {
		return fmt.Errorf("client types barrel: %w", err)
	}

	// 5. client/errors.ts — re-exports all error types/factories for frontend use.
	if err := emitClientErrorsBarrel(a, dir); err != nil {
		return fmt.Errorf("client errors barrel: %w", err)
	}

	// 6. client/package.json with per-module exports + types + errors.
	return emitClientPackageJSON(a, dir)
}

// emitModuleApi writes client/{moduleLower}Api.ts.
func emitModuleApi(a ast.AST, mod ast.Module, dir string) error {
	moduleLower := strings.ToLower(mod.Name)
	apiName := moduleLower + "Api"

	// Check if any action in this module uses query params.
	hasQuery := false
	for _, act := range mod.Actions {
		if act.Query != "" {
			hasQuery = true
			break
		}
	}

	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	if hasQuery {
		sb.WriteString("import { get, post, put, patch, del, buildQueryString } from './_internal';\n")
	} else {
		sb.WriteString("import { get, post, put, patch, del } from './_internal';\n")
	}

	usedTypes := emitter.CollectUsedTypes(a, mod)
	if len(usedTypes) > 0 {
		sb.WriteString(fmt.Sprintf("import type { %s } from '../types';\n", strings.Join(usedTypes, ", ")))
	}
	sb.WriteString("\n")

	sb.WriteString(fmt.Sprintf("export const %s = {\n", apiName))
	for _, act := range mod.Actions {
		writeAction(&sb, mod, act)
	}

	// Emit typed error code constants if any actions define errors.
	if emitter.HasErrors(mod) {
		sb.WriteString("  errors: {\n")
		for _, act := range mod.Actions {
			if len(act.Errors) == 0 {
				continue
			}
			camelAction := emitter.ToCamelCase(act.Name)
			sb.WriteString(fmt.Sprintf("    %s: {\n", camelAction))
			for _, errName := range act.Errors {
				code := emitter.ErrorCode(act.Name, errName)
				camelErr := emitter.ToCamelCase(errName)
				sb.WriteString(fmt.Sprintf("      %s: '%s',\n", camelErr, code))
			}
			sb.WriteString("    },\n")
		}
		sb.WriteString("  } as const,\n")
	}

	sb.WriteString("};\n")

	return os.WriteFile(filepath.Join(dir, moduleLower+"Api.ts"), []byte(sb.String()), 0644)
}

// emitApiBarrel writes client/api.ts that re-exports everything and provides
// the unified `api` object for convenience.
func emitApiBarrel(a ast.AST, dir string) error {
	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	sb.WriteString("export { VeldApiError, isApiError, isErrorCode } from './_internal';\n")
	sb.WriteString("export * from './types';\n")
	sb.WriteString("export * from './errors';\n")

	for _, mod := range a.Modules {
		moduleLower := strings.ToLower(mod.Name)
		apiName := moduleLower + "Api"
		sb.WriteString(fmt.Sprintf("export { %s } from './%sApi';\n", apiName, moduleLower))
	}

	sb.WriteString("\n// Unified namespace — import { api } from '@veld/client' for convenience.\n")
	for _, mod := range a.Modules {
		moduleLower := strings.ToLower(mod.Name)
		sb.WriteString(fmt.Sprintf("import { %sApi as _%sApi } from './%sApi';\n", moduleLower, moduleLower, moduleLower))
	}
	sb.WriteString("\nexport const api = {\n")
	for _, mod := range a.Modules {
		moduleLower := strings.ToLower(mod.Name)
		sb.WriteString(fmt.Sprintf("  %s: _%sApi,\n", mod.Name, moduleLower))
	}
	sb.WriteString("};\n")

	return os.WriteFile(filepath.Join(dir, "api.ts"), []byte(sb.String()), 0644)
}

// emitClientPackageJSON writes client/package.json with per-module exports.
func emitClientPackageJSON(a ast.AST, dir string) error {
	var sb strings.Builder
	sb.WriteString("{\n")
	sb.WriteString("  \"name\": \"@veld/client\",\n")
	sb.WriteString("  \"version\": \"0.0.0\",\n")
	sb.WriteString("  \"private\": true,\n")
	sb.WriteString("  \"types\": \"./api.ts\",\n")
	sb.WriteString("  \"exports\": {\n")
	sb.WriteString("    \".\": \"./api.ts\",\n")
	sb.WriteString("    \"./types\": \"./types.ts\",\n")
	sb.WriteString("    \"./errors\": \"./errors.ts\"")
	for _, mod := range a.Modules {
		moduleLower := strings.ToLower(mod.Name)
		sb.WriteString(fmt.Sprintf(",\n    \"./%sApi\": \"./%sApi.ts\"", moduleLower, moduleLower))
	}
	sb.WriteString("\n  }\n}\n")
	return os.WriteFile(filepath.Join(dir, "package.json"), []byte(sb.String()), 0644)
}

// emitClientTypesBarrel writes client/types.ts that re-exports all types from
// the generated types/ directory, so frontend consumers can:
//
//	import type { User } from '@veld/client/types';
func emitClientTypesBarrel(a ast.AST, dir string) error {
	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	sb.WriteString("// Re-exports all types for frontend convenience.\n")
	sb.WriteString("export * from '../types';\n")
	return os.WriteFile(filepath.Join(dir, "types.ts"), []byte(sb.String()), 0644)
}

// emitClientErrorsBarrel writes client/errors.ts that re-exports the client-side
// error utilities plus all backend error types/factories, so frontend consumers can:
//
//	import { VeldApiError, isApiError } from '@veld/client/errors';
func emitClientErrorsBarrel(a ast.AST, dir string) error {
	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	sb.WriteString("// Re-exports client-side error utilities.\n")
	sb.WriteString("export { VeldApiError, isApiError, isErrorCode } from './_internal';\n")

	// Also re-export backend error types if they exist.
	hasErrors := false
	for _, mod := range a.Modules {
		if emitter.HasErrors(mod) {
			hasErrors = true
			break
		}
	}
	if hasErrors {
		sb.WriteString("\n// Backend error types and factories:\n")

		exported := make(map[string]bool)
		// Mark client-side exports as already exported to avoid collisions.
		exported["VeldApiError"] = true
		exported["isApiError"] = true
		exported["isErrorCode"] = true

		for _, mod := range a.Modules {
			if !emitter.HasErrors(mod) {
				continue
			}
			moduleLower := strings.ToLower(mod.Name)
			allNames := emitter.CollectErrorExports(mod)

			// Filter out names already exported by a previous module.
			var unique []string
			for _, name := range allNames {
				if !exported[name] {
					exported[name] = true
					unique = append(unique, name)
				}
			}

			if len(unique) == len(allNames) {
				// No conflicts — safe to use export *.
				sb.WriteString(fmt.Sprintf("export * from '../errors/%s.errors';\n", moduleLower))
			} else if len(unique) > 0 {
				// Conflicts detected — use explicit named exports for unique names only.
				sb.WriteString(fmt.Sprintf("export { %s } from '../errors/%s.errors';\n",
					strings.Join(unique, ", "), moduleLower))
			}
			// If len(unique) == 0, skip entirely.
		}
	}

	return os.WriteFile(filepath.Join(dir, "errors.ts"), []byte(sb.String()), 0644)
}
